    toggleChangeDetails: function(element) {
        const details = element.nextElementSibling;
        if (!details || !details.classList.contains('change-details')) return;
        const isOpen = details.classList.contains('change-details-open');
        if (isOpen) {
            details.style.maxHeight = '0';
            details.classList.remove('change-details-open');
        } else {
            details.classList.add('change-details-open');
            details.style.maxHeight = details.scrollHeight + 'px';
        }
        const btn = element.querySelector('.change-expand-btn svg');
        if (btn) btn.style.transform = isOpen ? '' : 'rotate(180deg)';
        element.classList.toggle('expanded', !isOpen);
    },


