    voteChangelogItem: function(changeKey, voteType) {
        const votes = { ...(store.state.changelogVotes || {}) };
        const current = votes[changeKey] || { helpful: 0, notHelpful: 0, voted: null };
        if (current.voted === voteType) {
            current[voteType]--;
            current.voted = null;
        } else {
            if (current.voted) current[current.voted]--;
            current[voteType]++;
            current.voted = voteType;
        }
        votes[changeKey] = current;
        store.setState({ changelogVotes: votes });
        localStorage.setItem('vaultlister_changelog_votes', JSON.stringify(votes));
        renderApp(pages.changelog());
    },


