    // Send a message in the current conversation,


    sendVaultBuddyMessage: async function() {
        const input = document.getElementById('vault-buddy-input');
        if (!input) return;

        const message = input.value.trim();
        if (!message) return;

        const conversationId = store.state.vaultBuddyCurrentConversation?.id;
        if (!conversationId) return;

        // Clear input
        input.value = '';

        // Optimistically add user message to UI
        const userMessage = {
            id: 'temp_' + Date.now(),
            role: 'user',
            content: message,
            created_at: new Date().toISOString()
        };

        const currentMessages = store.state.vaultBuddyMessages || [];
        store.setState({
            vaultBuddyMessages: [...currentMessages, userMessage],
            vaultBuddyLoading: true
        });

        // Re-render to show user message and loading
        if (store.state.currentPage) {
            renderApp(pages[store.state.currentPage]());
            setTimeout(() => {
                const messagesEl = document.getElementById('vault-buddy-messages');
                if (messagesEl) messagesEl.scrollTop = messagesEl.scrollHeight;
            }, 50);
        }

        try {
            await api.ensureCSRFToken();
            const data = await api.post('/chatbot/message', {
                conversation_id: conversationId,
                message: message
            });

            if (data.success && data.message) {
                // Add assistant response
                const updatedMessages = store.state.vaultBuddyMessages || [];
                store.setState({
                    vaultBuddyMessages: [...updatedMessages, data.message],
                    vaultBuddyLoading: false
                });
            } else {
                store.setState({ vaultBuddyLoading: false });
            }
        } catch (error) {
            console.error('Failed to send message:', error);
            store.setState({ vaultBuddyLoading: false });
            toast.error('Failed to send message');
        }

        // Re-render to show response
        if (store.state.currentPage) {
            renderApp(pages[store.state.currentPage]());
            setTimeout(() => {
                const messagesEl = document.getElementById('vault-buddy-messages');
                if (messagesEl) messagesEl.scrollTop = messagesEl.scrollHeight;
            }, 50);
        }
    },

    // Delete a conversation,


    deleteVaultBuddyConversation: async function(conversationId) {
        if (!await modals.confirm('Are you sure you want to delete this conversation?', { title: 'Delete Conversation', confirmText: 'Delete', danger: true })) return;

        try {
            await api.ensureCSRFToken();
            await api.delete(`/chatbot/conversations/${conversationId}`);

            // If we're viewing this conversation, go back to list
            if (store.state.vaultBuddyCurrentConversation?.id === conversationId) {
                this.backToVaultBuddyList();
            } else {
                // Just reload the list
                await this.loadVaultBuddyConversations();
                if (store.state.currentPage) {
                    renderApp(pages[store.state.currentPage]());
                }
            }

            toast.success('Conversation deleted');
        } catch (error) {
            console.error('Failed to delete conversation:', error);
            toast.error('Failed to delete conversation');
        }
    },

