    // Load roadmap features from API,


    showRoadmapDetail: function(featureId) {
        const features = store.state.roadmapFeatures || [];
        const feature = features.find(f => f.id === featureId);
        if (!feature) { toast.error('Feature not found'); return; }

        const progressPercent = feature.status === 'completed' ? 100 :
                                feature.status === 'in_progress' ? (feature.progress || 50) : 0;
        const statusLabels = { planned: 'Planned', in_progress: 'In Progress', completed: 'Completed' };
        const statusColors = { planned: 'var(--gray-500)', in_progress: 'var(--primary-500)', completed: 'var(--success)' };

        modals.show(`
            <div class="modal-header">
                <h2 class="modal-title">${escapeHtml(feature.title)}</h2>
                <button class="modal-close" aria-label="Close" onclick="modals.close()">${components.icon('close')}</button>
            </div>
            <div class="modal-body">
                <div style="display: flex; gap: 12px; margin-bottom: 16px; align-items: center;">
                    <span class="feature-status-badge ${feature.status}" style="font-size: 13px; padding: 4px 12px;">
                        ${feature.status === 'completed' ? '&#10003; ' : feature.status === 'in_progress' ? '&#9673; ' : '&#9675; '}
                        ${statusLabels[feature.status] || feature.status}
                    </span>
                    ${feature.category ? '<span class="badge badge-outline">' + escapeHtml(feature.category) + '</span>' : ''}
                    <span style="color: var(--gray-500); font-size: 13px;">${feature.votes || 0} votes</span>
                </div>

                ${feature.description ? '<div style="color: var(--gray-600); margin-bottom: 16px; line-height: 1.6;">' + escapeHtml(feature.description) + '</div>' : '<div style="color: var(--gray-400); margin-bottom: 16px; font-style: italic;">No description available.</div>'}

                ${feature.status === 'in_progress' ? '<div style="margin-bottom: 16px;"><div style="font-size: 12px; color: var(--gray-500); margin-bottom: 4px;">Progress</div><div style="height: 8px; background: var(--gray-200); border-radius: 4px; overflow: hidden;"><div style="height: 100%; width: ' + progressPercent + '%; background: var(--primary-500); border-radius: 4px;"></div></div><div style="font-size: 12px; color: var(--gray-500); margin-top: 4px;">' + progressPercent + '% complete</div></div>' : ''}

                ${feature.eta ? '<div style="margin-bottom: 12px;"><span style="font-size: 12px; font-weight: 600; color: var(--gray-500);">Expected: </span><span style="font-size: 13px;">' + escapeHtml(feature.eta) + '</span></div>' : ''}

                ${feature.dependencies && feature.dependencies.length > 0 ? '<div style="margin-bottom: 12px;"><span style="font-size: 12px; font-weight: 600; color: var(--gray-500);">Dependencies: </span>' + feature.dependencies.map(function(d) { return '<span class="badge badge-sm badge-outline" style="margin-right: 4px;">' + escapeHtml(d) + '</span>'; }).join('') + '</div>' : ''}

                <div style="display: flex; gap: 8px; margin-top: 20px; padding-top: 16px; border-top: 1px solid var(--gray-200);">
                    <button class="btn ${feature.user_voted ? 'btn-primary' : 'btn-secondary'}" onclick="modals.close(); handlers.voteRoadmapFeature('${feature.id}')">
                        ${components.icon('star', 16)} ${feature.user_voted ? 'Remove Vote' : 'Vote for This'}
                    </button>
                    <button class="btn btn-secondary" onclick="modals.close()">Close</button>
                </div>
            </div>
        `);
    },


    submitFeedbackForm: async function(event) {
        event.preventDefault();

        const form = event.target;
        const formData = {
            type: store.state.feedbackFormType || 'feature',
            category: form.querySelector('#feedback-category').value || null,
            title: form.querySelector('#feedback-title').value,
            description: form.querySelector('#feedback-description').value,
            is_anonymous: form.querySelector('#feedback-anonymous')?.checked || false
        };

        // Add screenshot if present
        if (store.state.feedbackScreenshotData) {
            formData.screenshot_data = store.state.feedbackScreenshotData;
            formData.screenshot_mime = store.state.feedbackScreenshotMime;
        }

        // Validation
        if (!formData.title.trim()) {
            toast.warning('Please enter a title for your feedback');
            form.querySelector('#feedback-title')?.focus();
            return;
        }

        if (!formData.description.trim()) {
            toast.warning('Please enter a description for your feedback');
            form.querySelector('#feedback-description')?.focus();
            return;
        }

        try {
            await api.ensureCSRFToken();
            const response = await api.post('/feedback', formData);

            toast.success('Feedback submitted successfully!');

            // Reset form
            form.reset();
            store.setState({
                feedbackFormType: 'feature',
                feedbackFormCategory: '',
                feedbackScreenshot: null,
                feedbackScreenshotData: null,
                feedbackScreenshotMime: null,
                similarFeedback: []
            });

            // Add to user feedback list
            const userFeedback = store.state.userFeedback || [];
            userFeedback.unshift(response.feedback);
            store.setState({ userFeedback });

            // Re-render page
            renderApp(pages.submitFeedback());
        } catch (error) {
            console.error('Error submitting feedback:', error);
            toast.error('Failed to submit feedback. Please try again.');
        }
    },


