    // Submit new post,


    submitCreatePost: async function(event) {
        event.preventDefault();
        const form = event.target;
        const formData = new FormData(form);

        const postData = {
            type: formData.get('type'),
            title: formData.get('title'),
            content: formData.get('content'),
            tags: formData.get('tags') ? formData.get('tags').split(',').map(t => t.trim()).filter(Boolean) : []
        };

        // Add sale details for success stories
        if (postData.type === 'success') {
            const salePrice = parseFloat(formData.get('salePrice'));
            const profit = parseFloat(formData.get('profit'));

            if (!isNaN(salePrice) && !isNaN(profit)) {
                postData.sale_details = {
                    sale_price: salePrice,
                    profit: profit,
                    platform: formData.get('platform') || ''
                };
            }
        }

        try {
            await api.post('/community/posts', postData);
            toast.success('Post created successfully!');
            modals.close();
            await handlers.loadCommunity();
        } catch (error) {
            toast.error('Failed to create post: ' + error.message);
        }
    },

