    _showWalkthroughStep: function(page, stepIndex, steps) {
        const step = steps[stepIndex];
        const isLast = stepIndex === steps.length - 1;
        const isFirst = stepIndex === 0;

        modals.show(`
            <div class="modal-header">
                <h2>${components.icon('navigation', 20)} Walkthrough: Step ${stepIndex + 1} of ${steps.length}</h2>
                <button class="modal-close" aria-label="Close" onclick="modals.close()">${components.icon('x', 20)}</button>
            </div>
            <div class="modal-body">
                <div class="walkthrough-progress mb-4" style="display: flex; gap: 4px;">
                    ${steps.map((_, i) => `<div style="flex: 1; height: 4px; border-radius: 2px; background: ${i <= stepIndex ? 'var(--primary-500)' : 'var(--gray-200)'};"></div>`).join('')}
                </div>
                <h3 class="text-lg font-bold mb-2">${step.title}</h3>
                <p class="text-gray-600 mb-4">${step.desc}</p>
                <div class="p-3 bg-blue-50 rounded-lg border border-blue-200">
                    <p class="text-sm text-blue-800"><strong>Action:</strong> ${step.target}</p>
                </div>
            </div>
            <div class="modal-footer">
                ${!isFirst ? `<button class="btn btn-secondary" onclick="handlers._showWalkthroughStep('${page}', ${stepIndex - 1}, ${JSON.stringify(steps).replace(/'/g, "\\'")})">Previous</button>` : '<span></span>'}
                ${isLast
                    ? `<button class="btn btn-success" onclick="modals.close(); router.navigate('${page}'); toast.success('Walkthrough complete!');">Go to ${page.replace('-', ' ').replace(/\b\w/g, l => l.toUpperCase())}</button>`
                    : `<button class="btn btn-primary" onclick="handlers._showWalkthroughStep('${page}', ${stepIndex + 1}, ${JSON.stringify(steps).replace(/'/g, "\\'")})">Next Step</button>`
                }
            </div>
        `);
    },

